import React from 'react';
import Skills from './Skills';
import '../styles/Projects.css';

const Projects = () => {
  const projects = [
    {
      title: 'Predicting Crypto Price',
      technologies: ['Python', 'Finance API', 'scikit-learn', 'Random Forest', 'Artificial Neural Networks', 'Seaborn', 'Jupyter Notebook', 'XGBoost'],
      highlights: [
        'The project focuses on predicting Bitcoin cryptocurrency prices using historical market data and machine learning techniques. It analyzes past price trends to forecast future Bitcoin values. It aims to improve medical image analysis and assist doctors in detecting retinal abnormalities more efficiently',
        'The system uses retinal image datasets such as DRIVE and STARE, which contain annotated images with ground truth vessel masks. These datasets help train and evaluate deep learning models for accurate vessel segmentation',
        'Image preprocessing techniques such as contrast enhancement (CLAHE), noise reduction using Gaussian filtering, and normalization are applied. These steps improve vessel visibility and prepare the retinal images for deep learning model training',
        'Several deep learning models like U-Net, CNN, VGG-19, DenseNet-169, ResNet-101, and EfficientNet are implemented for retinal vessel segmentation. These models learn complex vessel patterns and perform pixel-level classification of vessel and non-vessel regions',
        'The models are evaluated using metrics such as accuracy, F1-score, ROC-AUC, sensitivity, and specificity to measure segmentation performance. Results show that U-Net and EfficientNet achieve the best accuracy (~98%), making them suitable for clinical and telemedicine applications',
      ],
      
    },

    {
      title: 'Digital Retinal Images for Vessel Extraction',
      technologies: ['Python', 'TensorFlow', 'U-Net', 'CNN', 'VGG-19', 'CLAHE', 'Gaussian Filtering', 'STARE Dataset'],
      highlights: [
        'The project focuses on automatically extracting blood vessels from retinal images to support diagnosis of diseases such as diabetic retinopathy, glaucoma, and cardiovascular disorders',
        'The dataset is collected from Yahoo Finance using the YFinance API, containing information such as open, close, high, low prices, and trading volume. This data is cleaned and preprocessed before model training',
        'Feature engineering is applied to extract useful indicators like moving averages, lag variables, and sentiment-related features to improve prediction accuracy. These features help models learn important patterns in Bitcoin price movements',
        'Model performance is evaluated using metrics like MAE, MSE, RMSE, and R², and results show that Random Forest and LSTM provide the best prediction accuracy. The study demonstrates how advanced analytics can support better cryptocurrency market insights',
      ],
      
    },
    
    {
      title: 'Hand Gesture Based Virtual Mouse',
      technologies: ['Python', 'MediaPipe', 'Flask/Django', 'Machine Learning', 'Human-Computer Interaction', 'Gesture Recognition', 'Real-Time Processing'],
      highlights: [
        'Developed a hand gesture-based virtual mouse leveraging HCI (Human-Computer Interaction) principles to replace physical mouse interactions',
        'Implemented real-time gesture recognition for cursor control and user interaction',
        'Designed a JWT-based secure authentication system for user management',
        'Integrated personalized recommendation algorithms, increasing user engagement by 45% through data-driven features',
      ],

    },
    {
      title: 'Deep Learning Approaches For Detecting Colorectal Polyp',
      technologies: ['Python', 'PyTorch', 'Deep Learning', 'Residual U-Net', 'OpenCV','CVCClinicDB dataset', 'Real-time inference','Matplotlib',  ],
      highlights: [
        'Implemented Residual U-Net architecture for colorectal polyp detection using CVCClinicDB dataset to improve early cancer diagnosis',
        'Developed a Django-based frontend integrated with deep learning models for real-time polyp detection',
        'Enabled potential integration with Computer-Aided Diagnosis (CAD) systems for clinical applications',
        'Focused on real-time inference, model deployment, and usability for healthcare workflows',
      ],

    },
  ];
    
  
}
export default Projects;
